{
  "schema_version": "0.1",
  "mode": "design",
  "workflow_kind": "dynamic",
  "dependencies": {
    "parallel_units": true,
    "edges": [
      {
        "from": "route_audit_batch",
        "to": "final_report",
        "type": "data",
        "reason": "the final report consumes all per-route audit results and therefore must wait for batch reconciliation"
      }
    ],
    "capacity_constraints": []
  },
  "dynamic": {
    "batch": {
      "handle": "route_audit_batch",
      "item_identity_source": "launch manifest of 40 route-file identities"
    },
    "await": {
      "join": "all",
      "k": null,
      "wake_when": "when all expected route-audit identities have reached a terminal status"
    },
    "accounting": {
      "expected_identity_source": "launch snapshot",
      "terminal_statuses": [
        "succeeded",
        "failed",
        "cancelled",
        "timed_out"
      ],
      "duplicate_policy": "open",
      "unknown_policy": "open",
      "failure_policy": "open",
      "partial_policy": "open",
      "complete_label_requires": [
        "expected_vs_represented",
        "no_duplicates",
        "no_unknown_identities",
        "terminal_status_accounted",
        "no_unresolved_identities"
      ]
    },
    "reductions": [
      {
        "name": "batch_summary_layer",
        "expected_identity_source": "launch manifest of 40 route-file identities",
        "represented_identity_source": "immutable per-route audit result records collected for the batch",
        "status_count_source": "terminal status tallies derived from per-route audit result records",
        "unresolved_identity_source": "expected route-file identities lacking a represented terminal result or ending failed, cancelled, or timed_out"
      }
    ],
    "final_reconciliation": {
      "summary_identity_source": "batch summary identities",
      "checks": [
        "expected_vs_represented",
        "duplicate",
        "unknown",
        "terminal_status",
        "unresolved"
      ]
    }
  },
  "open_points": [
    {
      "key": "duplicate_policy",
      "question": "If more than one result is represented for the same route-file identity, should reconciliation reject the batch or tolerate duplicates?"
    },
    {
      "key": "unknown_policy",
      "question": "If a result appears for a route-file identity not present in the launch manifest, should reconciliation reject it or ignore it?"
    },
    {
      "key": "failure_policy",
      "question": "May the final report be published when one or more route audits end failed, cancelled, or timed_out?"
    },
    {
      "key": "partial_policy",
      "question": "May an incomplete final report be published when expected route-audit identities remain unresolved or unrepresented?"
    }
  ],
  "scenarios": [
    {
      "kind": "positive",
      "expected": "all 40 launched route-file identities are represented exactly once with terminal statuses, reconciliation passes all checks, and the control plane can label the batch complete for final reporting"
    },
    {
      "kind": "missing",
      "expected": "one or more launched route-file identities are not represented by terminal audit results, reconciliation marks unresolved identities, and a complete batch label is withheld"
    },
    {
      "kind": "duplicate",
      "expected": "the same route-file identity is represented more than once in audit results, reconciliation detects duplicates, and handling remains open pending duplicate_policy"
    },
    {
      "kind": "failed",
      "expected": "one or more route audits reach failed terminal status, status accounting includes them as unresolved for completeness, and report publication remains open pending failure_policy"
    },
    {
      "kind": "timed_out",
      "expected": "one or more route audits reach timed_out terminal status, status accounting includes them as unresolved for completeness, and report publication remains open pending failure_policy"
    },
    {
      "kind": "unknown",
      "expected": "an audit result appears for a route-file identity outside the 40-item launch manifest, reconciliation flags an unknown identity, and handling remains open pending unknown_policy"
    },
    {
      "kind": "partial_refused",
      "expected": "if partial publication is refused, any unresolved, failed, cancelled, timed_out, duplicate, or unknown identity prevents publishing the final report"
    },
    {
      "kind": "partial_allowed",
      "expected": "if partial publication is allowed, the control plane may publish a final report annotated as incomplete despite unresolved, failed, cancelled, timed_out, duplicate, or unknown identities"
    }
  ],
  "boundary": {
    "control_plane": [
      "launch",
      "await",
      "reconcile"
    ],
    "target_data_plane": [
      "workers",
      "scheduling",
      "persistence",
      "rate_limiting",
      "backpressure"
    ]
  }
}

